package agents.Kotlin.content

import agents.BaseActivePersona
import core.types.ProjectContext
import core.base.AuditRule
import core.base.AuditFinding
import core.base.StrategicFinding

/**
 * 🧬 Dr. Generic — PhD in Generics & Type Algebra (TypeScript)
 * Generated by Sovereign Forge.
 */
class GenericPersona(projectRoot: String? = null) : BaseActivePersona(projectRoot) {
    init {
        this.name = "Generic"
        this.emoji = "🧬"
        this.role = "PhD TypeScript Type Algebraist"
        this.phd_identity = "Generics & Type Algebra (TypeScript)"
        this.stack = "Kotlin"
        this.healingPrompt = "Fix the following generic programming or type abstraction issue. Improve generic constraints and resolve type erasure problems. Return ONLY the corrected code or a specific diff."
    }

    override suspend fun execute(context: ProjectContext): List<Any> {
        this.setContext(context)
        return this.performAudit()
    }

    override fun getAuditRules(): Map<String, Any> {
        return mapOf(
            "extensions" to listOf([".kt"]),
            "rules" to listOf<AuditRule>(
                // [
          {
                    "regex": "<[^>]*<[^>]*<[^>]*>>",
                    "issue": "Complexidade: Generics com 3+ níveis de aninhamento — simplificar com type aliases.",
                    "severity": "medium"
          },
          {
                    "regex": "extends\\s+infer\\s+\\w+.*extends\\s+infer",
                    "issue": "Magia Negra: Múltiplos \"infer\" condicionais — difícil de manter.",
                    "severity": "high"
          },
          {
                    "regex": "type\\s+\\w+<[^>]*>\\s*=\\s*\\w+<[^>]*>\\s*extends\\s",
                    "issue": "Tipo Condicional: Conditional type — verifique se não há alternativa simples.",
                    "severity": "low"
          },
          {
                    "regex": "as\\s+unknown\\s+as\\s+",
                    "issue": "Double Cast: \"as unknown as X\" — forte indicador de design errado.",
                    "severity": "high"
          }
]
            )
        )
    }

    fun performAudit() {
        println("☕ [${name}] Starting fleet-wide audit via Hub PhD...")
    }

    fun reasonAboutObjective(objective: String, file: String, context: String) {
        println("☕ [${name}] Delegating reasoning for '${objective}' to Hub...")
    }

    fun delegateHealingToHub(file: String, issue: String) {
        println("☕ [${name}] Delegating healing for '$issue' to Hub...")
    }
}
